    public class ParserHardcoder
    {
        private static string EscapeCSharpString(string value)
        {
            if (value == null) return string.Empty;
            return value.Replace("\\", "\\\\").Replace("\"", "\\\"");
        }

        private static void AppendStringArray(StringBuilder strb, string varName, IEnumerable<string> values)
        {
            strb.AppendLine("var " + varName + " = new string[] {");
            foreach (var v in values)
            {
                strb.AppendLine("    \"" + EscapeCSharpString(v) + "\",");
            }
            strb.AppendLine("};");
        }

        private static void AppendIntArray(StringBuilder strb, string varName, IEnumerable<int> values)
        {
            strb.AppendLine("var " + varName + " = new int[] {");
            int i = 0;
            foreach (var v in values)
            {
                strb.Append(v);
                strb.Append(",");
                i++;
                if (i % 30 == 0)
                    strb.AppendLine();
                else
                    strb.Append(' ');
            }
            if (i % 32 != 0)
                strb.AppendLine();
            strb.AppendLine("};");
        }

        public static string GenerateHardcode(ParserData data)
        {
            StringBuilder strb = new StringBuilder();

            var terminals = data.table.terminals.ToList();
            var nonterminals = data.table.nonterminals.ToList();
            var symbols = terminals.Concat(nonterminals).ToList();
            var symbolIndex = symbols
                .Select((name, idx) => (name, idx))
                .ToDictionary(x => x.name, x => x.idx);
            var terminalIndex = terminals
                .Select((name, idx) => (name, idx))
                .ToDictionary(x => x.name, x => x.idx);

            AppendStringArray(strb, "terminals", terminals);
            strb.AppendLine("for (int i = 0; i < terminals.Length; ++i) NewTerminal(terminals[i]);");

            AppendStringArray(strb, "nonterminals", nonterminals);
            strb.AppendLine("for (int i = 0; i < nonterminals.Length; ++i) NewNonterminal(nonterminals[i]);");

            var productions = data.grammerSet.productions.Select(p => p.ToExpression());
            AppendStringArray(strb, "productions", productions);
            strb.AppendLine("for (int i = 0; i < productions.Length; ++i) NewProduction(productions[i]);");

            var stateNames = data.lalrStates.OrderBy(s => s.idx).Select(s => s.name);
            AppendStringArray(strb, "stateNames", stateNames);
            strb.AppendLine("for (int i = 0; i < stateNames.Length; ++i) NewState(i, stateNames[i]);");

            strb.AppendLine("outputData.table.stateCount = stateNames.Length;");
            strb.AppendLine("outputData.table.terminals = terminals.ToList();");
            strb.AppendLine("outputData.table.nonterminals = nonterminals.ToList();");

            List<int> actionData = new List<int>();
            foreach (var tuple in data.table.GetAllActions())
            {
                int typeNum = tuple.Item3.type == ACTION_TYPE.Shift ? 0 :
                              tuple.Item3.type == ACTION_TYPE.Reduce ? 1 :
                              tuple.Item3.type == ACTION_TYPE.Accept ? 2 : 3;
                actionData.Add(tuple.Item1);
                actionData.Add(terminalIndex[tuple.Item2]);
                actionData.Add(typeNum);
                actionData.Add(tuple.Item3.num);
            }
            AppendIntArray(strb, "actionData", actionData);
            strb.AppendLine("for (int i = 0; i < actionData.Length; i += 4)");
            strb.AppendLine("{");
            strb.AppendLine("    int state = actionData[i];");
            strb.AppendLine("    int termIdx = actionData[i + 1];");
            strb.AppendLine("    int type = actionData[i + 2];");
            strb.AppendLine("    int num = actionData[i + 3];");
            strb.AppendLine("    ACTION act = type == 0 ? ACTION.Shift(num) :");
            strb.AppendLine("                 type == 1 ? ACTION.Reduce(num) :");
            strb.AppendLine("                 type == 2 ? ACTION.Acc : ACTION.Err;");
            strb.AppendLine("    outputData.table.SetACTION(state, terminals[termIdx], act);");
            strb.AppendLine("}");

            List<int> gotoData = new List<int>();
            foreach (var tuple in data.table.GetAllGotos())
            {
                gotoData.Add(tuple.Item1);
                gotoData.Add(symbolIndex[tuple.Item2]);
                gotoData.Add(tuple.Item3.stateId);
            }
            AppendIntArray(strb, "gotoData", gotoData);
            strb.AppendLine("for (int i = 0; i < gotoData.Length; i += 3)");
            strb.AppendLine("{");
            strb.AppendLine("    int state = gotoData[i];");
            strb.AppendLine("    int symbolIdx = gotoData[i + 1];");
            strb.AppendLine("    int target = gotoData[i + 2];");
            strb.AppendLine("    outputData.table.SetGOTO(state, terminals.Length > symbolIdx ? terminals[symbolIdx] : nonterminals[symbolIdx - terminals.Length], target);");
            strb.AppendLine("}");


            return strb.ToString();
        }

        public static void GenerateHardcodeHere(string hardcodefilePath, ParserData data)
        {
            string content = GenerateHardcode(data);
            ReplaceRegionContent(hardcodefilePath, content);
        }

        public static void ReplaceRegionContent(string filePath, string newContent)
        {
            if(System.IO.File.Exists(filePath) == false)
                throw new Exception("Harcode File Path Not Exist!");

            string regionStart = "#region HardCode";
            string regionEnd = "#endregion";

            // 读取所有文件内容
            string[] lines = System.IO.File.ReadAllLines(filePath);
            List<string> updatedLines = new List<string>();
            bool insideRegion = false;

            foreach(var line in lines)
            {
                if (line.TrimStart().StartsWith("///Generate Time:"))
                {
                    continue;
                }

                if(line.Trim() == regionStart)
                {
                    // 开始替换区域
                    insideRegion = true;
                    updatedLines.Add(line); // 保留开始标记
                    updatedLines.Add(newContent); // 插入新内容
                    continue;
                }
                if(line.Trim() == regionEnd && insideRegion)
                {
                    // 结束替换区域
                    insideRegion = false;
                    updatedLines.Add(line); // 保留结束标记
                    continue;
                }
                if(!insideRegion)
                {
                    // 不在替换区域内，保留原内容
                    updatedLines.Add(line);
                }
            }

            updatedLines.Add($"///Generate Time:{System.DateTime.Now.ToString()}");

            // 将修改后的内容写回文件
            System.IO.File.WriteAllLines(filePath, updatedLines, Encoding.UTF8);
            Gizbox.GixConsole.WriteLine("替换完成...");
        }


        public static ParserData GenerateParser()
        {
            ParserHardcoder hardcoder = new ParserHardcoder();
            hardcoder.StartGenrate();
            return hardcoder.outputData;
        }


        private ParserData outputData = new ParserData();

        private Dictionary<string, Terminal> terminalDic => outputData.grammerSet.terminalDict;
        private Dictionary<string, Nonterminal> nonterminalDic => outputData.grammerSet.nonterminalDict;
        private Dictionary<string, Symbol> symbolDic => outputData.grammerSet.symbolDict;




        private void NewTerminal(string t)
        {
            Terminal terminal = new Terminal(outputData.grammerSet, t);
        }

        private void NewNonterminal(string nt)
        {
            Nonterminal nonterminal = new Nonterminal(outputData.grammerSet, nt);
        }

        private void NewProduction(Nonterminal head, Symbol[] body)
        {
            Production p = new Production(outputData.grammerSet, head, body);
        }

        private void NewProduction(string expression)
        {
            string[] segments = expression.Split(' ');
            if (segments.Length < 2) return;
            if (segments[1] != "->") return;

            Nonterminal head = nonterminalDic[segments[0]];
            if (segments.Length == 3 && segments[2] == "ε")
            {
                NewProduction(head, new Symbol[0]);
                return;
            }

            Symbol[] body = new Symbol[segments.Length - 2];
            for (int i = 2; i < segments.Length; ++i)
            {
                body[i - 2] = symbolDic[segments[i]];
            }
            NewProduction(head, body);
        }

        private void NewState(int idx, string name)
        {
            State state = new State(idx, name, new LR1ItemSet());
            outputData.lalrStates.Add(state);
        }

        public void StartGenrate()
        {
            outputData.table = new ParseTable();
            outputData.lalrStates = new List<State>();

            HardCodePart();
        }

